// ==================== Custom Timber Trees ====================

class FileLoggingTree(private val application: Application) : Timber.Tree() {
    
    private val executor = Executors.newSingleThreadExecutor()
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        executor.execute {
            try {
                val logDir = File(application.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()
                
                val fileName = "app_log_${fileDateFormat.format(Date())}.txt"
                val logFile = File(logDir, fileName)
                
                val priorityChar = when (priority) {
                    Log.VERBOSE -> "V"
                    Log.DEBUG -> "D"
                    Log.INFO -> "I"
                    Log.WARN -> "W"
                    Log.ERROR -> "E"
                    Log.ASSERT -> "A"
                    else -> "?"
                }
                
                val timestamp = dateFormat.format(Date())
                val threadName = Thread.currentThread().name
                val logEntry = "$timestamp [$priorityChar/$tag] [Thread:$threadName] $message\n"
                
                FileWriter(logFile, true).use { writer ->
                    writer.append(logEntry)
                    if (t != null) {
                        val sw = StringWriter()
                        t.printStackTrace(PrintWriter(sw))
                        writer.append("$timestamp [$priorityChar/$tag] STACKTRACE:\n$sw\n")
                    }
                }
                
                // Rotate logs - keep last 7 days
                cleanOldLogs(logDir, 7)
                
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }
    
    private fun cleanOldLogs(logDir: File, retainDays: Int) {
        val cutoff = System.currentTimeMillis() - (retainDays * 24 * 60 * 60 * 1000L)
        logDir.listFiles()?.filter { it.lastModified() < cutoff }?.forEach { it.delete() }
    }
}

class CrashReportingTree : Timber.Tree() {
    
    private val recentLogs = ConcurrentLinkedQueue<String>()
    private val maxRecentLogs = 500
    private val dateFormat = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val entry = "${dateFormat.format(Date())} [$tag] $message"
        recentLogs.add(entry)
        while (recentLogs.size > maxRecentLogs) {
            recentLogs.poll()
        }
        
        if (priority >= Log.ERROR) {
            // In production, send to crash reporting service
            // FirebaseCrashlytics.getInstance().log(entry)
            if (t != null) {
                // FirebaseCrashlytics.getInstance().recordException(t)
            }
        }
    }
    
    fun getRecentLogs(): List<String> = recentLogs.toList()
}

