            else -> Log.VERBOSE
        }
        
        val logMethod: (String) -> Unit = when (logLevel) {
            Log.WARN -> { msg -> Timber.w(msg) }
            Log.ERROR -> { msg -> Timber.e(msg) }
            Log.INFO -> { msg -> Timber.i(msg) }
            else -> { msg -> Timber.v(msg) }
        }
        
        logMethod("=== API RESPONSE [$requestId] ===")
        logMethod("Session: $sessionId")
