        logMethod("Content-Type: ${contentType ?: "N/A"}")
        logMethod("Content-Length: ${contentLength ?: "N/A"}")
        logMethod("Response Time: ${responseTimeMs}ms")
        logMethod("From Cache: $fromCache")
        
        if (responseHeaders.isNotEmpty()) {
            logMethod("Response Headers:")
            responseHeaders.forEach { (key, value) ->
                logMethod("  $key: $value")
            }
        }
        
        if (responseBody != null) {
            val truncatedBody = if (responseBody.length > 5000) {
                "${responseBody.substring(0, 5000)}... [TRUNCATED, total: ${responseBody.length} chars]"
            } else {
                responseBody
            }
            logMethod("Response Body:")
            logMethod(truncatedBody)
        }
        
        // Performance warnings
        if (responseTimeMs > 3000) {
            Timber.w("SLOW API RESPONSE: ${responseTimeMs}ms for $method $url")
        }
        
        // Error logging
        if (statusCode >= 400) {
            Timber.e("API ERROR: $statusCode for $method $url - ${responseBody?.take(500) ?: "No body"}")
        }
        
        logMethod("=================================")
    }
    
