    // ==================== Exception Logging ====================
    
    fun logExceptionFull(
        throwable: Throwable,
        context: String = "General",
        additionalInfo: Map<String, String> = emptyMap()
    ) {
        Timber.e("╔══════════════════════════════════════════")
        Timber.e("║ EXCEPTION DETAILS")
        Timber.e("╠══════════════════════════════════════════")
        Timber.e("║ Context: $context")
        Timber.e("║ Session: $sessionId")
        Timber.e("║ Timestamp: ${dateFormat.format(Date())}")
        Timber.e("║ Thread: ${Thread.currentThread().name} (id: ${Thread.currentThread().id})")
        Timber.e("║ Exception Type: ${throwable::class.java.name}")
        Timber.e("║ Message: ${throwable.message ?: "No message"}")
        
        if (additionalInfo.isNotEmpty()) {
            Timber.e("║ Additional Info:")
            additionalInfo.forEach { (key, value) ->
                Timber.e("║   $key: $value")
            }
        }
        
        // Full stack trace
        Timber.e("╠══════════════════════════════════════════")
        Timber.e("║ STACK TRACE:")
        val sw = StringWriter()
        throwable.printStackTrace(PrintWriter(sw))
        sw.toString().split("\n").forEach { line ->
            Timber.e("║ $line")
        }
        
        // Log cause chain
        var cause = throwable.cause
        var causeDepth = 1
        while (cause != null) {
            Timber.e("╠══════════════════════════════════════════")
            Timber.e("║ CAUSE #$causeDepth: ${cause::class.java.name}")
            Timber.e("║ Message: ${cause.message ?: "No message"}")
            Timber.e("║ Stack Trace:")
            val causeSw = StringWriter()
            cause.printStackTrace(PrintWriter(causeSw))
            causeSw.toString().split("\n").take(20).forEach { line ->
                Timber.e("║ $line")
            }
            cause = cause.cause
            causeDepth++
            if (causeDepth > 10) {
                Timber.e("║ [Cause chain truncated at depth 10]")
                break
            }
        }
        
        // Suppressed exceptions
        if (throwable.suppressed.isNotEmpty()) {
            Timber.e("╠══════════════════════════════════════════")
            Timber.e("║ SUPPRESSED EXCEPTIONS (${throwable.suppressed.size}):")
            throwable.suppressed.forEachIndexed { index, suppressed ->
                Timber.e("║ Suppressed #${index + 1}: ${suppressed::class.java.name}: ${suppressed.message}")
            }
        }
        
        // Memory info at time of exception
        val runtime = Runtime.getRuntime()
        val usedMemory = (runtime.totalMemory() - runtime.freeMemory()) / (1024 * 1024)
        val maxMemory = runtime.maxMemory() / (1024 * 1024)
        Timber.e("╠══════════════════════════════════════════")
        Timber.e("║ MEMORY STATE:")
        Timber.e("║ Used: ${usedMemory}MB / Max: ${maxMemory}MB (${(usedMemory * 100 / maxMemory)}%)")
        Timber.e("║ Free: ${runtime.freeMemory() / (1024 * 1024)}MB")
        
        Timber.e("╚══════════════════════════════════════════")
    }
    
