    fun <T> measureAndLog(operationName: String, block: () -> T): T {
        val startTime = System.currentTimeMillis()
        var success = true
        try {
            return block()
        } catch (e: Exception) {
            success = false
            throw e
        } finally {
            val duration = System.currentTimeMillis() - startTime
            logPerformanceMetric(operationName, duration, success)
        }
    }
    
