    // ==================== Utility Methods ====================
    
    private fun maskSensitiveData(data: String): String {
        if (data.length <= 4) return "****"
        return "${data.take(2)}${"*".repeat(data.length - 4)}${data.takeLast(2)}"
    }
    
    private fun sanitizeHeader(key: String, value: String): String {
        val sensitiveHeaders = listOf("authorization", "cookie", "set-cookie", "x-api-key", "api-key", "token")
        return if (sensitiveHeaders.any { key.lowercase().contains(it) }) {
            if (value.length > 10) "${value.take(6)}...[REDACTED]...${value.takeLast(4)}"
            else "[REDACTED]"
        } else {
            value
        }
    }
    
    private fun sanitizeDbParam(value: Any?): String {
        return when (value) {
            null -> "NULL"
            is String -> {
                if (value.length > 200) "'${value.take(200)}...[TRUNCATED, ${value.length} chars]'"
                else "'$value'"
            }
            is ByteArray -> "[BLOB, ${value.size} bytes]"
            else -> value.toString()
        }
    }
    
    // ==================== Log Export ====================
    
    fun getLogFiles(): List<File> {
        if (!::application.isInitialized) return emptyList()
        val logDir = File(application.filesDir, "logs")
        return logDir.listFiles()?.toList()?.sortedByDescending { it.lastModified() } ?: emptyList()
    }
    
    fun exportLogs(): String {
        val sb = StringBuilder()
        sb.appendLine("=== LOG EXPORT ===")
        sb.appendLine("Session: $sessionId")
        sb.appendLine("Export Time: ${dateFormat.format(Date())}")
        sb.appendLine("==================")
        
        getLogFiles().forEach { file ->
            sb.appendLine("\n--- File: ${file.name} ---")
            try {
                sb.appendLine(file.readText())
            } catch (e: Exception) {
                sb.appendLine("[Error reading file: ${e.message}]")
            }
        }
        
        return sb.toString()
    }
}

// ==================== OkHttp Interceptor for API Logging ====================

/* 
 * Usage with OkHttp/Retrofit:
 * Add this interceptor to your OkHttpClient.Builder
 */

class ComprehensiveLoggingInterceptor : okhttp3.Interceptor {
    
    override fun intercept(chain: okhttp3.Interceptor.Chain): okhttp3.Response {
        val request = chain.request()
        val startTime = System.currentTimeMillis()
        
        // Extract request details
        val method = request.method
        val url = request.url.toString()
        val headers = mutableMapOf<String, String>()
        request.headers.forEach { (name, value) ->
            headers[name] = value
        }
        
        // Read request body
        val requestBody = request.body?.let { body ->
            try {
                val buffer = okio.Buffer()
                body.writeTo(buffer)
                buffer.readUtf8()
            } catch (e: Exception) {
                "[Error reading request body: ${e.message}]"
            }
        }
        
        // Log request
        val requestId = AppLogger.logApiRequest(
            method = method,
            url = url,
            headers = headers,
            requestBody = requestBody,
            contentType = request.body?.contentType()?.toString()
        )
        
        // Execute request
        val response: okhttp3.Response
        try {
            response = chain.proceed(request)
        } catch (e: Exception) {
            val elapsed = System.currentTimeMillis() - startTime
            AppLogger.logApiError(
                requestId = requestId,
                method = method,
                url = url,
                exception = e,
                responseTimeMs = elapsed
            )
            throw e
        }
        
        val elapsed = System.currentTimeMillis() - startTime
        
        // Extract response details
        val responseHeaders = mutableMapOf<String, String>()
        response.headers.forEach { (name, value) ->
            responseHeaders[name] = value
        }
        
        // Read response body (carefully, as it can only be consumed once)
        val responseBody = response.peekBody(Long.MAX_VALUE).string()
        
        // Log response
        AppLogger.logApiResponse(
            requestId = requestId,
            method = method,
            url = url,
            statusCode = response.code,
            statusMessage = response.message,
            responseHeaders = responseHeaders,
            responseBody = responseBody,
            contentType = response.body?.contentType()?.toString(),
            contentLength = response.body?.contentLength(),
            responseTimeMs = elapsed,
            fromCache = response.cacheResponse != null
        )
        
        return response
    }
}

// ==================== Database Query Logger Wrapper ====================

class DatabaseQueryLogger {
    
    companion object {
        
        fun <T> logQuery(
            queryType: String,
            tableName: String,
            rawQuery: String,
            parameters: Map<String, Any?> = emptyMap(),
            selectionArgs: Array<String>? = null,
            callerInfo: String? = null,
            block: () -> T
        ): T {
            val startTime = System.currentTimeMillis()
            var resultCount: Int? = null
            var rowsAffected = 0
            
            try {
                val result = block()
                
                val elapsed = System.currentTimeMillis() - startTime
                
                // Try to determine result count
                when (result) {
                    is List<*> -> resultCount = result.size
                    is Int -> rowsAffected = result
                    is Long -> rowsAffected = result.toInt()
                }
                
                AppLogger.logDatabaseQuery(
                    queryType = queryType,
                    tableName = tableName,
                    rawQuery = rawQuery,
                    parameters = parameters,
                    selectionArgs = selectionArgs,
                    executionTimeMs = elapsed,
                    rowsAffected = rowsAffected,
                    resultCount = resultCount,
                    callerInfo = callerInfo
                )
                
                return result
            } catch (e: Exception) {
                val elapsed = System.currentTimeMillis() - startTime
                
                AppLogger.logDatabaseQuery(
                    queryType = queryType,
                    tableName = tableName,
                    rawQuery = rawQuery,
                    parameters = parameters,
                    selectionArgs = selectionArgs,
                    executionTimeMs = elapsed,
                    callerInfo = callerInfo
                )
                
                AppLogger.logExceptionFull(e, "DatabaseQuery", mapOf(
                    "queryType" to queryType,
                    "table" to tableName,
                    "query" to rawQuery
                ))
                
                throw e
            }
        }
    }
}

