    fun demonstrateAuthLogging() {
        // Log authentication attempt
        AppLogger.logAuthAttempt(
            username = "john.doe@example.com",
            authMethod = "password",
            ipAddress = "192.168.1.100",
            deviceId = "device-abc-123",
            additionalMetadata = mapOf(
                "app_version" to "1.2.3",
                "platform" to "Android"
            )
        )
        
        // Log successful authentication
        AppLogger.logAuthSuccess(
            username = "john.doe@example.com",
            authMethod = "password",
            tokenType = "Bearer",
            tokenExpiry = System.currentTimeMillis() + 3600000,
            permissions = listOf("read", "write", "admin"),
            responseTimeMs = 450
        )
        
        // Log failed authentication
        AppLogger.logAuthFailure(
            username = "john.doe@example.com",
            authMethod = "password",
            failureReason = "Invalid credentials",
            errorCode = 401,
            attemptsRemaining = 3,
            responseTimeMs = 200
        )
        
        // Log token refresh
        AppLogger.logAuthTokenRefresh(
            success = true,
            oldTokenExpiry = System.currentTimeMillis(),
            newTokenExpiry = System.currentTimeMillis() + 3600000
        )
    }
    
    fun demonstrateDatabaseLogging() {
        // Log a SELECT query
